### 3. **accordion.tsx** - Radix UI Primitive Wrapper

**Complete File:**
```typescript
"use client"

import * as React from "react"
import { ChevronDownIcon } from "lucide-react"
import { Accordion as AccordionPrimitive } from "radix-ui"

import { cn } from "@/lib/utils"

function Accordion({
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Root>) {
  return <AccordionPrimitive.Root data-slot="accordion" {...props} />
}

function AccordionItem({
  className,
  className,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Item>) {
  return (
    <AccordionPrimitive.Item
      data-slot="accordion-item"
      className={cn("border-b last:border-b-0", className)}
      {...props}
    />
  )
}

function AccordionTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Trigger>) {
  return (
    <AccordionPrimitive.Header className="flex">
      <AccordionPrimitive.Trigger
        data-slot="accordion-trigger"
        className={cn(
          "flex flex-1 items-start justify-between gap-4 rounded-md py-4 text-left text-sm font-medium transition-all outline-none hover:underline focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50 [&[data-state=open]>svg]:rotate-180",
          className
        )}
        {...props}
      >
        {children}
        <ChevronDownIcon className="pointer-events-none size-4 shrink-0 translate-y-0.5 text-muted-foreground transition-transform duration-200" />
      </AccordionPrimitive.Trigger>
    </AccordionPrimitive.Header>
  )
}

function AccordionContent({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Content>) {
  return (
    <AccordionPrimitive.Content
      data-slot="accordion-content"
      className="overflow-hidden text-sm data-[state=closed]:animate-accordion-up data-[state=open]:animate-accordion-down"
      {...props}
    >
      <div className={cn("pt-0 pb-4", className)}>{children}</div>
    </AccordionPrimitive.Content>
  )
}

export { Accordion, AccordionItem, AccordionTrigger, AccordionContent }
```

**Key Patterns:**
- **Minimal Wrappers**: Simple passthroughs with added styling
- **Header Wrapping**: `AccordionTrigger` wraps the trigger in `AccordionPrimitive.Header`
- **Data Slot Attributes**: Consistent `data-slot` on all components
- **Data-State Selectors**: Uses `data-[state=open]` and `data-[state=closed]` from Radix
- **Child Components**: All exports are individual functions, not nested objects
- **SVG Styling**: Icon styling with pseudo-selectors like `[&[data-state=open]>svg]:rotate-180`

---

### 4. **lib/utils.ts** - Utility Function

**Complete File:**
```typescript
import { clsx, type ClassValue } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

export function absoluteUrl(path: string) {
  return `${process.env.NEXT_PUBLIC_APP_URL}${path}`
}
```

**Key Pattern:**
- **cn() Utility**: Combines `clsx` (for conditional classes) + `twMerge` (for Tailwind conflict resolution)
- **ClassValue Type**: Accepts any valid class input (string, array, object)
- **Function Signature**: Simple, spreads inputs for flexibility

---

## Summary of Compound Component Patterns

### Architecture Patterns:
1. **Context-Based** (Carousel): For stateful, interconnected components with complex logic
2. **Primitive Wrappers** (Tabs, Accordion): For wrapping Radix UI primitives with styling
3. **No Nested Objects**: All parts exported as separate functions

### Typing Patterns:
- Extend `React.ComponentProps<typeof PrimitiveComponent>` 
- Add variant props via `VariantProps<typeof variantSchema>`
- Use `&` to combine type intersections
- Export type aliases (e.g., `type CarouselApi`)

### Styling Patterns:
- **cn()** for merging classes everywhere
- **CVA (class-variance-authority)** for variant management (exported for external use)
- **Data attributes** for CSS selectors: `data-slot`, `data-state`, `data-variant`, `data-orientation`
- **CSS groups** with group modifiers: `group/tabs`, `group-data-[variant=line]/tabs-list:`

### Data Slot Convention:
Every component has a `data-slot="component-name"` attribute for:
- CSS targeting
- Testing hooks
- Component identification

### Props Pattern:
- Extract specific props (className, variant, etc.)
- Use `...props` for remaining HTML attributes
- Spread into the underlying element

This is the exact pattern you should replicate for your Stepper component.

