"use client"

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

// --- Stepper Context ---

type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// --- StepperItem Context ---

type StepperItemContextProps = {
  step: number
  state: "completed" | "active" | "pending"
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// --- Stepper ---

function Stepper({
  orientation = "horizontal",
  activeStep,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  orientation?: "horizontal" | "vertical"
  activeStep: number
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-row items-start"
            : "flex-col items-start",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// --- StepperItem ---

function StepperItem({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep, orientation } = useStepper()

  const state: "completed" | "active" | "pending" =
    step < activeStep
      ? "completed"
      : step === activeStep
        ? "active"
        : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-col items-center"
            : "flex-row items-start",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// --- StepperTrigger ---

const stepperTriggerVariants = cva(
  "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      state: {
        completed:
          "border-primary bg-primary text-primary-foreground",
        active:
          "border-primary bg-primary text-primary-foreground",
        pending:
          "border-muted-foreground/40 bg-background text-muted-foreground",
      },
    },
    defaultVariants: {
      state: "pending",
    },
  }
)

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      className={cn(stepperTriggerVariants({ state }), className)}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

// --- StepperTitle ---

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

// --- StepperDescription ---

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// --- StepperSeparator ---

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "shrink-0 rounded-full transition-colors",
        orientation === "horizontal"
          ? "mt-4 h-0.5 flex-1"
          : "ml-4 w-0.5 flex-1",
        state === "completed" ? "bg-primary" : "bg-muted",
        className
      )}
      {...props}
    />
  )
}

// --- StepperContent ---

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-4", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Create your account",
  },
  {
    step: 2,
    title: "Profile",
    description: "Set up your profile",
  },
  {
    step: 3,
    title: "Complete",
    description: "You're all set!",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="flex w-full max-w-2xl flex-col gap-8">
      <Stepper activeStep={activeStep} className="w-full">
        {steps.map(({ step, title, description }, index) => (
          <React.Fragment key={step}>
            <StepperItem step={step} className="flex-1">
              <div className="flex flex-col items-center gap-2">
                <StepperTrigger
                  onClick={() => setActiveStep(step)}
                  aria-label={`Go to step ${step}: ${title}`}
                />
                <StepperTitle>{title}</StepperTitle>
                <StepperDescription>{description}</StepperDescription>
              </div>
            </StepperItem>
            {index < steps.length - 1 && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>

      {steps.map(({ step, title }) => (
        <StepperContent key={step} step={step}>
          <div className="rounded-lg border p-6">
            <h3 className="mb-2 text-lg font-semibold">Step {step}: {title}</h3>
            <p className="text-sm text-muted-foreground">
              {step === 1 && "Enter your email address and create a password to get started."}
              {step === 2 && "Tell us a bit about yourself to personalize your experience."}
              {step === 3 && "Your account has been created successfully. Welcome aboard!"}
            </p>
          </div>
        </StepperContent>
      ))}

      <div className="flex gap-2">
        <Button
          variant="outline"
          onClick={() => setActiveStep((s) => Math.max(1, s - 1))}
          disabled={activeStep === 1}
        >
          Previous
        </Button>
        <Button
          onClick={() => setActiveStep((s) => Math.min(steps.length, s + 1))}
          disabled={activeStep === steps.length}
        >
          Next
        </Button>
      </div>
    </div>
  )
}

