"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Create your account",
    content:
      "Enter your email address and create a password to get started with your new account.",
  },
  {
    step: 2,
    title: "Profile",
    description: "Set up your profile",
    content:
      "Tell us a bit about yourself to personalize your experience and help others find you.",
  },
  {
    step: 3,
    title: "Complete",
    description: "You're all set!",
    content:
      "Your account has been created successfully. Welcome aboard — you're ready to get started!",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="flex w-full max-w-2xl flex-col gap-6 p-4">
      <Stepper activeStep={activeStep} className="w-full">
        {/* Step indicators row */}
        <div className="flex flex-row items-start w-full">
          {steps.map(({ step, title, description }, index) => (
            <StepperItem
              key={step}
              step={step}
              className={index < steps.length - 1 ? "flex-1" : "flex-initial"}
            >
              <div className="flex flex-col items-center gap-1.5">
                <StepperTrigger
                  onClick={() => setActiveStep(step)}
                  aria-label={`Go to step ${step}: ${title}`}
                />
                <StepperTitle className="text-center">{title}</StepperTitle>
                <StepperDescription className="text-center">
                  {description}
                </StepperDescription>
              </div>
              {index < steps.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </div>

        {/* Step content panels */}
        {steps.map(({ step, title, content }) => (
          <StepperContent key={step} step={step}>
            <div className="rounded-lg border p-6">
              <h3 className="mb-2 text-base font-semibold">
                Step {step}: {title}
              </h3>
              <p className="text-sm text-muted-foreground">{content}</p>
            </div>
          </StepperContent>
        ))}

        {/* Navigation */}
        <div className="flex gap-2">
          <Button
            variant="outline"
            onClick={() => setActiveStep((s) => Math.max(1, s - 1))}
            disabled={activeStep === 1}
          >
            Previous
          </Button>
          <Button
            onClick={() =>
              setActiveStep((s) => Math.min(steps.length, s + 1))
            }
            disabled={activeStep === steps.length}
          >
            Next
          </Button>
        </div>
      </Stepper>
    </div>
  )
}

