        {/* Step indicators row */}
        <div className="flex flex-row items-start w-full">
          {steps.map(({ step, title, description }, index) => (
            <StepperItem
              key={step}
              step={step}
              className={index < steps.length - 1 ? "flex-1" : "flex-initial"}
            >
              <div className="flex flex-col items-center gap-1.5">
                <StepperTrigger
                  onClick={() => setActiveStep(step)}
                  aria-label={`Go to step ${step}: ${title}`}
                />
                <StepperTitle className="text-center">{title}</StepperTitle>
                <StepperDescription className="text-center">
                  {description}
                </StepperDescription>
              </div>
              {index < steps.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </div>

        {/* Step content panels */}
        {steps.map(({ step, title, content }) => (
          <StepperContent key={step} step={step}>
            <div className="rounded-lg border p-6">
              <h3 className="mb-2 text-base font-semibold">
                Step {step}: {title}
              </h3>
              <p className="text-sm text-muted-foreground">{content}</p>
            </div>
          </StepperContent>
        ))}

        {/* Navigation */}
        <div className="flex gap-2">
          <Button
            variant="outline"
            onClick={() => setActiveStep((s) => Math.max(1, s - 1))}
            disabled={activeStep === 1}
          >
            Previous
          </Button>
          <Button
            onClick={() =>
              setActiveStep((s) => Math.min(steps.length, s + 1))
            }
            disabled={activeStep === steps.length}
          >
            Next
          </Button>
        </div>
      </Stepper>
    </div>
  )
}

